import os

def create_files():
    files = {
        "backend/app/models/user.py": "from sqlalchemy import Column, String, Boolean, Integer, DateTime\nfrom sqlalchemy.orm import relationship\nfrom .base import BaseModel\n\nclass User(BaseModel):\n    __tablename__ = 'users'\n    email = Column(String, unique=True, index=True, nullable=False)\n    hashed_password = Column(String, nullable=False)\n    is_active = Column(Boolean, default=True)\n    role = Column(String, default=\"user\")\n    email_verified = Column(Boolean, default=False)\n    failed_login_attempts = Column(Integer, default=0)\n    locked_until = Column(DateTime(timezone=True), nullable=True)\n    refresh_token = Column(String, nullable=True)\n    \n    scans = relationship(\"Scan\", back_populates=\"user\", cascade=\"all, delete-orphan\")\n    audit_logs = relationship(\"AuditLog\", back_populates=\"user\", cascade=\"all, delete-orphan\")\n",
        "backend/app/security/jwt.py": "from jose import jwt, JWTError\nfrom datetime import datetime, timedelta\nfrom typing import Optional\nfrom app.config.settings import settings\nfrom app.exceptions.custom import UnauthorizedException\n\ndef create_access_token(data: dict) -> str:\n    to_encode = data.copy()\n    expire = datetime.utcnow() + timedelta(minutes=settings.ACCESS_TOKEN_EXPIRE_MINUTES)\n    to_encode.update({\"exp\": expire})\n    return jwt.encode(to_encode, settings.SECRET_KEY, algorithm=settings.ALGORITHM)\n\ndef create_refresh_token(data: dict) -> str:\n    to_encode = data.copy()\n    # Refresh token expires in 7 days\n    expire = datetime.utcnow() + timedelta(days=7)\n    to_encode.update({\"exp\": expire, \"type\": \"refresh\"})\n    return jwt.encode(to_encode, settings.SECRET_KEY, algorithm=settings.ALGORITHM)\n\ndef decode_token(token: str) -> dict:\n    try:\n        payload = jwt.decode(token, settings.SECRET_KEY, algorithms=[settings.ALGORITHM])\n        return payload\n    except JWTError:\n        raise UnauthorizedException(\"Invalid or expired token\")\n",
        "backend/app/middleware/auth.py": "from fastapi import Request\nfrom starlette.middleware.base import BaseHTTPMiddleware\nfrom app.security.jwt import decode_token\nfrom app.exceptions.custom import UnauthorizedException\nfrom fastapi.responses import JSONResponse\n\nclass JWTAuthMiddleware(BaseHTTPMiddleware):\n    async def dispatch(self, request: Request, call_next):\n        public_paths = [\"/api/login\", \"/api/register\", \"/api/refresh\", \"/docs\", \"/openapi.json\", \"/health\", \"/version\"]\n        \n        # Allow preflight requests\n        if request.method == \"OPTIONS\":\n            return await call_next(request)\n            \n        # Skip auth for public paths\n        if any(request.url.path.startswith(path) for path in public_paths):\n            return await call_next(request)\n            \n        auth_header = request.headers.get(\"Authorization\")\n        if not auth_header or not auth_header.startswith(\"Bearer \"):\n            return JSONResponse(status_code=401, content={\"error\": \"Missing or invalid authentication token\", \"code\": \"UNAUTHORIZED\"})\n            \n        token = auth_header.split(\" \")[1]\n        try:\n            payload = decode_token(token)\n            request.state.user = payload\n        except UnauthorizedException as e:\n            return JSONResponse(status_code=401, content={\"error\": str(e.message), \"code\": e.code})\n            \n        return await call_next(request)\n",
        "backend/app/services/auth_service.py": "from sqlalchemy.ext.asyncio import AsyncSession\nfrom app.repositories.user_repo import user_repo\nfrom app.schemas.user import UserCreate, UserLogin\nfrom app.security.hashing import get_password_hash, verify_password\nfrom app.security.jwt import create_access_token, create_refresh_token, decode_token\nfrom app.exceptions.custom import DomainException, UnauthorizedException\nfrom app.models.audit import AuditLog\nfrom datetime import datetime, timedelta\n\nclass AuthService:\n    @staticmethod\n    async def register(db: AsyncSession, user_in: UserCreate):\n        existing = await user_repo.get_by_email(db, user_in.email)\n        if existing:\n            raise DomainException(\"Email already registered\", 400, \"EMAIL_EXISTS\")\n        hashed = get_password_hash(user_in.password)\n        user = await user_repo.create(db, {\"email\": user_in.email, \"hashed_password\": hashed})\n        \n        # Audit log\n        audit = AuditLog(user_id=user.id, action=\"register\", details=\"User registered successfully\")\n        db.add(audit)\n        await db.commit()\n        return user\n\n    @staticmethod\n    async def login(db: AsyncSession, user_in: UserLogin):\n        user = await user_repo.get_by_email(db, user_in.email)\n        if not user:\n            raise UnauthorizedException(\"Incorrect email or password\")\n            \n        # Check lockout\n        if user.locked_until and user.locked_until > datetime.utcnow().replace(tzinfo=user.locked_until.tzinfo):\n            raise UnauthorizedException(\"Account is locked. Try again later.\")\n            \n        if not verify_password(user_in.password, user.hashed_password):\n            user.failed_login_attempts += 1\n            if user.failed_login_attempts >= 5:\n                user.locked_until = datetime.utcnow() + timedelta(minutes=15)\n            db.add(AuditLog(user_id=user.id, action=\"login_failed\", details=\"Invalid password attempt\"))\n            await db.commit()\n            raise UnauthorizedException(\"Incorrect email or password\")\n            \n        # Success\n        user.failed_login_attempts = 0\n        user.locked_until = None\n        refresh_token = create_refresh_token({\"sub\": user.email})\n        user.refresh_token = refresh_token\n        \n        db.add(AuditLog(user_id=user.id, action=\"login_success\", details=\"User logged in\"))\n        await db.commit()\n        \n        return {\n            \"access_token\": create_access_token({\"sub\": user.email}),\n            \"refresh_token\": refresh_token,\n            \"token_type\": \"bearer\",\n            \"user\": {\"id\": user.id, \"email\": user.email, \"role\": user.role}\n        }\n        \n    @staticmethod\n    async def refresh(db: AsyncSession, refresh_token: str):\n        try:\n            payload = decode_token(refresh_token)\n            if payload.get(\"type\") != \"refresh\":\n                raise UnauthorizedException(\"Invalid token type\")\n            email = payload.get(\"sub\")\n        except Exception:\n            raise UnauthorizedException(\"Invalid refresh token\")\n            \n        user = await user_repo.get_by_email(db, email)\n        if not user or user.refresh_token != refresh_token:\n            raise UnauthorizedException(\"Invalid refresh token\")\n            \n        new_access = create_access_token({\"sub\": user.email})\n        new_refresh = create_refresh_token({\"sub\": user.email})\n        user.refresh_token = new_refresh\n        await db.commit()\n        \n        return {\n            \"access_token\": new_access,\n            \"refresh_token\": new_refresh,\n            \"token_type\": \"bearer\"\n        }\n",
        "backend/app/controllers/auth_controller.py": "from fastapi import APIRouter, Depends, Response, Cookie\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom app.database.session import get_db\nfrom app.schemas.user import UserCreate, UserLogin, UserResponse\nfrom app.services.auth_service import AuthService\nfrom pydantic import BaseModel\nfrom typing import Optional\n\nrouter = APIRouter()\n\nclass LoginResponse(BaseModel):\n    access_token: str\n    token_type: str\n    user: dict\n\n@router.post(\"/register\", response_model=UserResponse)\nasync def register(user_in: UserCreate, db: AsyncSession = Depends(get_db)):\n    return await AuthService.register(db, user_in)\n\n@router.post(\"/login\", response_model=LoginResponse)\nasync def login(user_in: UserLogin, response: Response, db: AsyncSession = Depends(get_db)):\n    result = await AuthService.login(db, user_in)\n    # Set HttpOnly cookie for refresh token\n    response.set_cookie(\n        key=\"refresh_token\",\n        value=result[\"refresh_token\"],\n        httponly=True,\n        secure=True,\n        samesite=\"lax\",\n        max_age=7 * 24 * 60 * 60\n    )\n    return {\"access_token\": result[\"access_token\"], \"token_type\": result[\"token_type\"], \"user\": result[\"user\"]}\n\n@router.post(\"/refresh\")\nasync def refresh(response: Response, refresh_token: Optional[str] = Cookie(None), db: AsyncSession = Depends(get_db)):\n    if not refresh_token:\n        from app.exceptions.custom import UnauthorizedException\n        raise UnauthorizedException(\"No refresh token found\")\n    result = await AuthService.refresh(db, refresh_token)\n    response.set_cookie(\n        key=\"refresh_token\",\n        value=result[\"refresh_token\"],\n        httponly=True,\n        secure=True,\n        samesite=\"lax\",\n        max_age=7 * 24 * 60 * 60\n    )\n    return {\"access_token\": result[\"access_token\"], \"token_type\": result[\"token_type\"]}\n\n@router.post(\"/logout\")\nasync def logout(response: Response):\n    response.delete_cookie(\"refresh_token\")\n    return {\"status\": \"success\"}\n",
        "backend/app/main.py": "from fastapi import FastAPI\nfrom fastapi.responses import JSONResponse\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom app.config.settings import settings\nfrom app.routes.api import api_router\nfrom app.exceptions.custom import DomainException\nfrom app.exceptions.handlers import domain_exception_handler, general_exception_handler\nfrom app.middleware.security import SecurityHeadersMiddleware\nfrom app.middleware.rate_limit import RateLimitMiddleware\nfrom app.middleware.auth import JWTAuthMiddleware\n\napp = FastAPI(\n    title=settings.PROJECT_NAME,\n    version=settings.VERSION,\n    openapi_url=f\"{settings.API_V1_STR}/openapi.json\"\n)\n\n# CORS\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[\"http://localhost:3000\"],\n    allow_credentials=True,\n    allow_methods=[\"*\"],\n    allow_headers=[\"*\"],\n)\n\n# Middleware (Order matters: Auth inside CORS inside Security)\napp.add_middleware(JWTAuthMiddleware)\napp.add_middleware(SecurityHeadersMiddleware)\napp.add_middleware(RateLimitMiddleware)\n\n# Exception Handlers\napp.add_exception_handler(DomainException, domain_exception_handler)\napp.add_exception_handler(Exception, general_exception_handler)\n\n# Routes\napp.include_router(api_router, prefix=settings.API_V1_STR)\n\n@app.get(\"/health\", tags=[\"system\"])\nasync def health_check():\n    return {\"status\": \"healthy\"}\n\n@app.get(\"/version\", tags=[\"system\"])\nasync def get_version():\n    return {\"version\": settings.VERSION}\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Backend Stage 5 scaffolded.")
